        'hypnoVoiceLabel2': { TW: '催眠值 - 語音催眠', CN: '催眠值 - 语音催眠', EN: 'Hypnosis – Voice', JP: "催眠値 - 言語催眠", KR: "최면치 - 언어 최면", DE: 'Hypnose – Stimme', FR: 'Hypnose – Voix', RU: 'Гипноз – голос', UA: 'Гіпноз – голос' },
        'hypnoVoiceD2': { TW: '每次語音催眠增加的催眠值（0~20）。催眠狀態關閉則無效。', CN: '每次语音催眠增加的催眠值（0~20）。催眠状态关闭则无效。', EN: 'Hypnosis value added per voice hypnosis (0–20). No effect if Hypnotic state is off.', JP: "言語催眠1回ごとに増加する催眠値（0~20）。催眠状態がオフの場合は無効。", KR: "언어 최면 1회당 증가하는 최면치(0~20). 최면 상태가 꺼져 있으면 효과 없음.", DE: 'Hypnosewert pro Sprachhypnose (0–20). Ohne Wirkung, wenn Hypnosezustand aus ist.', FR: 'Valeur d\'hypnose ajoutée par hypnose vocale (0–20). Sans effet si l\'État hypnotique est désactivé.', RU: 'Значение гипноза за голосовой гипноз (0–20). Не действует, если Гипнотическое состояние выключено.', UA: 'Значення гіпнозу за голосовий гіпноз (0–20). Не діє, якщо Гіпнотичний стан вимкнено.' },
